package router

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"

	corev1 "k8s.io/api/core/v1"
	apierrors "k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"
)

const (
	SecretName           = "picod-router-identity"
	PrivateKeyKey        = "private.pem"
	PublicKeyKey         = "public.pem"
	DefaultNamespace     = "default"
	NamespaceEnvVar      = "AGENTCUBE_NAMESPACE"
)

// SecretManager manages JWT keys in Kubernetes secrets
type SecretManager struct {
	client     kubernetes.Interface
	namespace  string
	privateKey []byte
	publicKey  []byte
}

// NewSecretManager creates a new secret manager
func NewSecretManager() (*SecretManager, error) {
	namespace := os.Getenv(NamespaceEnvVar)
	if namespace == "" {
		namespace = DefaultNamespace
	}

	return &SecretManager{
		namespace: namespace,
	}, nil
}

// TryStoreOrLoadJWTKeySecret attempts to load existing keys or create new ones
func (s *SecretManager) TryStoreOrLoadJWTKeySecret(ctx context.Context) error {
	// Try to get in-cluster config
	config, err := rest.InClusterConfig()
	if err != nil {
		klog.Infof("Not running in-cluster, skipping JWT secret management: %v", err)
		return nil
	}

	client, err := kubernetes.NewForConfig(config)
	if err != nil {
		return fmt.Errorf("failed to create kubernetes client: %w", err)
	}
	s.client = client

	// Try to get existing secret
	secret, err := client.CoreV1().Secrets(s.namespace).Get(ctx, SecretName, metav1.GetOptions{})
	if err == nil {
		// Secret exists, load keys
		s.privateKey = secret.Data[PrivateKeyKey]
		s.publicKey = secret.Data[PublicKeyKey]
		klog.Info("Loaded JWT keys from existing secret")
		return nil
	}

	if !apierrors.IsNotFound(err) {
		return fmt.Errorf("failed to get secret: %w", err)
	}

	// Secret doesn't exist, generate new keys
	klog.Info("Generating new JWT key pair")
	privateKey, publicKey, err := generateKeyPair()
	if err != nil {
		return fmt.Errorf("failed to generate key pair: %w", err)
	}

	// Create secret
	newSecret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      SecretName,
			Namespace: s.namespace,
		},
		Type: corev1.SecretTypeOpaque,
		Data: map[string][]byte{
			PrivateKeyKey: privateKey,
			PublicKeyKey:  publicKey,
		},
	}

	_, err = client.CoreV1().Secrets(s.namespace).Create(ctx, newSecret, metav1.CreateOptions{})
	if err != nil {
		return fmt.Errorf("failed to create secret: %w", err)
	}

	s.privateKey = privateKey
	s.publicKey = publicKey
	klog.Info("Created new JWT secret")
	return nil
}

// GetPublicKey returns the public key
func (s *SecretManager) GetPublicKey() ([]byte, error) {
	if len(s.publicKey) == 0 {
		return nil, fmt.Errorf("public key not loaded")
	}
	return s.publicKey, nil
}

// GetPrivateKey returns the private key
func (s *SecretManager) GetPrivateKey() ([]byte, error) {
	if len(s.privateKey) == 0 {
		return nil, fmt.Errorf("private key not loaded")
	}
	return s.privateKey, nil
}

func generateKeyPair() (privateKeyPEM, publicKeyPEM []byte, err error) {
	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		return nil, nil, fmt.Errorf("failed to generate RSA key: %w", err)
	}

	privateKeyBytes := x509.MarshalPKCS1PrivateKey(privateKey)
	privateKeyPEM = pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: privateKeyBytes,
	})

	publicKeyBytes, err := x509.MarshalPKIXPublicKey(&privateKey.PublicKey)
	if err != nil {
		return nil, nil, fmt.Errorf("failed to marshal public key: %w", err)
	}

	publicKeyPEM = pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: publicKeyBytes,
	})

	return privateKeyPEM, publicKeyPEM, nil
}

