package router

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

// Proxy handles reverse proxying to sandboxes
type Proxy struct {
	jwtManager    *JWTManager
	transport     *http.Transport
}

// NewProxy creates a new proxy
func NewProxy(jwtManager *JWTManager) *Proxy {
	return &Proxy{
		jwtManager: jwtManager,
		transport: &http.Transport{
			MaxIdleConns:        100,
			MaxIdleConnsPerHost: 10,
			IdleConnTimeout:     90 * time.Second,
		},
	}
}

// Handler returns a gin handler for proxying to sandboxes
func (p *Proxy) Handler(sessionManager *SessionManager) gin.HandlerFunc {
	return func(c *gin.Context) {
		ctx := c.Request.Context()
		sessionID := c.GetHeader("x-agentcube-session-id")
		kind := c.GetString("kind")
		namespace := c.Param("namespace")
		name := c.Param("name")

		// Resolve sandbox
		sandbox, err := sessionManager.GetSandboxBySession(ctx, kind, namespace, name, sessionID)
		if err != nil {
			handleSessionError(c, err)
			return
		}

		// Update last activity
		sessionManager.UpdateLastActivity(ctx, sandbox.SessionID)

		// Determine upstream URL
		upstreamURL, err := p.determineUpstreamURL(sandbox, c.Param("path"))
		if err != nil {
			c.JSON(http.StatusNotFound, gin.H{"error": "no entry point found for sandbox"})
			return
		}

		// Create reverse proxy
		proxy := httputil.NewSingleHostReverseProxy(upstreamURL)
		proxy.Transport = p.transport

		// Custom director
		originalDirector := proxy.Director
		proxy.Director = func(req *http.Request) {
			originalDirector(req)
			p.modifyRequest(req, c, sandbox)
		}

		// Error handler
		proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
			p.handleProxyError(c, err)
		}

		// Modify response to add session header
		proxy.ModifyResponse = func(resp *http.Response) error {
			resp.Header.Set("x-agentcube-session-id", sandbox.SessionID)
			return nil
		}

		// Proxy the request
		proxy.ServeHTTP(c.Writer, c.Request)

		// Update last activity after request completes
		sessionManager.UpdateLastActivity(ctx, sandbox.SessionID)
	}
}

func (p *Proxy) determineUpstreamURL(sandbox *types.SandboxInfo, path string) (*url.URL, error) {
	if len(sandbox.EntryPoints) == 0 {
		return nil, fmt.Errorf("no entry points")
	}

	// Find matching entry point by path prefix
	var entryPoint *types.SandboxEntryPoint
	for _, ep := range sandbox.EntryPoints {
		if strings.HasPrefix(path, ep.Path) {
			entryPoint = &ep
			break
		}
	}

	// Use first entry point if no match
	if entryPoint == nil {
		entryPoint = &sandbox.EntryPoints[0]
	}

	// Build URL
	endpoint := entryPoint.Endpoint
	if entryPoint.Protocol != "" && !strings.HasPrefix(endpoint, "http://") && !strings.HasPrefix(endpoint, "https://") {
		endpoint = strings.ToLower(entryPoint.Protocol) + "://" + endpoint
	}

	return url.Parse(endpoint)
}

func (p *Proxy) modifyRequest(req *http.Request, c *gin.Context, sandbox *types.SandboxInfo) {
	// Normalize path
	path := c.Param("path")
	if path != "" && !strings.HasPrefix(path, "/") {
		path = "/" + path
	}
	req.URL.Path = path

	// Set forwarding headers
	req.Header.Set("X-Forwarded-Host", c.Request.Host)
	if c.Request.TLS != nil {
		req.Header.Set("X-Forwarded-Proto", "https")
	} else {
		req.Header.Set("X-Forwarded-Proto", "http")
	}

	// Set X-Forwarded-For
	clientIP := c.ClientIP()
	if prior := req.Header.Get("X-Forwarded-For"); prior != "" {
		clientIP = prior + ", " + clientIP
	}
	req.Header.Set("X-Forwarded-For", clientIP)

	// Add JWT for sandbox kinds
	if sandbox.Kind == types.SandboxKind || sandbox.Kind == types.SandboxClaimsKind {
		if p.jwtManager != nil {
			token, err := p.jwtManager.SignToken(map[string]interface{}{
				"session_id": sandbox.SessionID,
				"sandbox_id": sandbox.SandboxID,
			})
			if err != nil {
				klog.Warningf("Failed to sign JWT: %v", err)
			} else {
				req.Header.Set("Authorization", "Bearer "+token)
			}
		}
	}
}

func (p *Proxy) handleProxyError(c *gin.Context, err error) {
	errStr := err.Error()
	if strings.Contains(errStr, "connection refused") {
		c.JSON(http.StatusBadGateway, gin.H{"error": "sandbox unreachable"})
	} else if strings.Contains(errStr, "timeout") {
		c.JSON(http.StatusGatewayTimeout, gin.H{"error": "sandbox timeout"})
	} else {
		c.JSON(http.StatusBadGateway, gin.H{"error": "sandbox unreachable"})
	}
}

func handleSessionError(c *gin.Context, err error) {
	if apierrors.IsNotFound(err) {
		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
}

