package router

import (
	"net/http"
	"sync"

	"github.com/gin-gonic/gin"
)

// Semaphore implements a counting semaphore
type Semaphore struct {
	capacity int
	current  int
	mu       sync.Mutex
	cond     *sync.Cond
}

// NewSemaphore creates a new semaphore with the given capacity
func NewSemaphore(capacity int) *Semaphore {
	s := &Semaphore{
		capacity: capacity,
	}
	s.cond = sync.NewCond(&s.mu)
	return s
}

// Acquire acquires a slot in the semaphore
func (s *Semaphore) Acquire() bool {
	s.mu.Lock()
	defer s.mu.Unlock()

	if s.current >= s.capacity {
		return false
	}
	s.current++
	return true
}

// Release releases a slot in the semaphore
func (s *Semaphore) Release() {
	s.mu.Lock()
	s.current--
	s.mu.Unlock()
	s.cond.Signal()
}

// ConcurrencyMiddleware creates a middleware that limits concurrent requests
func ConcurrencyMiddleware(semaphore *Semaphore) gin.HandlerFunc {
	return func(c *gin.Context) {
		if !semaphore.Acquire() {
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error": "server overloaded, please try again later",
				"code":  "SERVER_OVERLOADED",
			})
			c.Abort()
			return
		}

		defer semaphore.Release()
		c.Next()
	}
}

