	"os"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

// Server is the HTTP server for the router
type Server struct {
	router          *gin.Engine
	config          *Config
	sessionManager  *SessionManager
	jwtManager      *JWTManager
	semaphore       *Semaphore
}

// NewServer creates a new router server
func NewServer(config *Config) (*Server, error) {
	if config.MaxConcurrentRequests <= 0 {
		config.MaxConcurrentRequests = 1000
	}

	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Logger())
	router.Use(gin.Recovery())

	// Initialize secret manager and JWT
	secretManager, err := NewSecretManager()
	if err != nil {
		return nil, fmt.Errorf("failed to create secret manager: %w", err)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	if err := secretManager.TryStoreOrLoadJWTKeySecret(ctx); err != nil {
		return nil, fmt.Errorf("failed to initialize JWT keys: %w", err)
	}

	privateKey, _ := secretManager.GetPrivateKey()
	publicKey, _ := secretManager.GetPublicKey()

	jwtManager, err := NewJWTManager(privateKey, publicKey)
	if err != nil {
		klog.Warningf("JWT manager not initialized: %v", err)
	}

	// Initialize store
	storage := store.Storage()

	// Read auth token from service account
	authToken := ""
	tokenBytes, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")
	if err == nil {
		authToken = string(tokenBytes)
	}

	// Initialize session manager
	sessionManager, err := NewSessionManager(storage, config.WorkloadManagerURL, authToken)
	if err != nil {
		return nil, err
	}

	server := &Server{
		router:         router,
		config:         config,
		sessionManager: sessionManager,
		jwtManager:     jwtManager,
		semaphore:      NewSemaphore(config.MaxConcurrentRequests),
	}

	server.setupRoutes()
	return server, nil
}

func (s *Server) setupRoutes() {
	// Health endpoints
	s.router.GET("/health/live", s.handleHealthLive)
	s.router.GET("/health/ready", s.handleHealthReady)

	// API v1 routes with concurrency limiting
	v1 := s.router.Group("/v1")
	v1.Use(ConcurrencyMiddleware(s.semaphore))
	{
		// Agent runtime invocations
		v1.GET("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleInvocation(types.AgentRuntimeKind))
		v1.POST("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleInvocation(types.AgentRuntimeKind))

		// Code interpreter invocations
		v1.GET("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleInvocation(types.CodeInterpreterKind))
		v1.POST("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleInvocation(types.CodeInterpreterKind))
	}
}

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error":  "session manager not available",
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

func (s *Server) handleInvocation(kind string) gin.HandlerFunc {
	proxy := NewProxy(s.jwtManager)
	return func(c *gin.Context) {
		c.Set("kind", kind)
		proxy.Handler(s.sessionManager)(c)
	}
}

// Start starts the HTTP server
func (s *Server) Start() error {
	addr := fmt.Sprintf(":%d", s.config.Port)
	klog.Infof("Starting router server on %s", addr)

	// Configure HTTP/2 with h2c
	h2s := &http2.Server{}
	handler := h2c.NewHandler(s.router, h2s)

	server := &http.Server{
		Addr:         addr,
		Handler:      handler,
		ReadTimeout:  30 * time.Second,
		IdleTimeout:  90 * time.Second,
	}

	if s.config.EnableTLS {
		if s.config.CertFile == "" || s.config.KeyFile == "" {
			return fmt.Errorf("TLS enabled but cert/key file not provided")
		}
		return server.ListenAndServeTLS(s.config.CertFile, s.config.KeyFile)
	}

	return server.ListenAndServe()
}

// Shutdown gracefully shuts down the server
func (s *Server) Shutdown(ctx context.Context) error {
	// Close store
	return store.Storage().Close()
}

