// handleProxyError handles proxy errors and returns appropriate responses
func handleProxyError(c *gin.Context, err error) {
	errMsg := err.Error()
	if containsAny(errMsg, []string{"connection refused", "no such host"}) {
		c.JSON(http.StatusBadGateway, gin.H{"error": "sandbox unreachable"})
		return
	}
	if containsAny(errMsg, []string{"timeout", "deadline exceeded"}) {
		c.JSON(http.StatusGatewayTimeout, gin.H{"error": "sandbox timeout"})
		return
	}
	c.JSON(http.StatusBadGateway, gin.H{"error": "sandbox unreachable"})
}

func containsAny(s, substrs []string) bool {
	for _, substr := range substrs {
		if contains(s, substr) {
			return true
		}
	}
	return false
}

func contains(s, substr string) bool {
	return len(s) >= len(substr) && (s == substr || len(substr) > 0 && containsSubstring(s, substr))
}

func containsSubstring(s, substr string) bool {
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}

// parseJSON parses JSON body into the given interface
func parseJSON(data []byte, v interface{}) error {
	return json.Unmarshal(data, v)
}

