)

// SessionManager handles session resolution and creation
type SessionManager struct {
	store              store.Store
	workloadManagerURL string
	authToken          string
}

// NewSessionManager creates a new session manager
func NewSessionManager(s store.Store, workloadManagerURL, authToken string) (*SessionManager, error) {
	if workloadManagerURL == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	return &SessionManager{
		store:              s,
		workloadManagerURL: workloadManagerURL,
		authToken:          authToken,
	}, nil
}

// GetSandboxBySession resolves or creates a sandbox for the given session
func (sm *SessionManager) GetSandboxBySession(ctx context.Context, kind, namespace, name string, sessionID string) (*types.SandboxInfo, error) {
	if sessionID != "" {
		// Try to load existing session
		sandbox, err := sm.store.GetSandboxBySessionID(ctx, sessionID)
		if err != nil {
			if err == store.ErrNotFound {
				return nil, fmt.Errorf("session not found: %s", sessionID)
			}
			return nil, err
		}
		return sandbox, nil
	}

	// Create new session via workload manager
	return sm.createSandbox(ctx, kind, namespace, name)
}

// createSandbox creates a new sandbox via the workload manager
func (sm *SessionManager) createSandbox(ctx context.Context, kind, namespace, name string) (*types.SandboxInfo, error) {
	url := fmt.Sprintf("%s/v1/%s", sm.workloadManagerURL, getResourcePath(kind))

	body := fmt.Sprintf(`{"kind":"%s","name":"%s","namespace":"%s"}`, kind, name, namespace)
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, url, strings.NewReader(body))
	if err != nil {
		return nil, err
	}

	req.Header.Set("Content-Type", "application/json")
	if sm.authToken != "" {
		req.Header.Set("Authorization", "Bearer "+sm.authToken)
	}

	client := &http.Client{Timeout: 30 * time.Second}
	resp, err := client.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode == http.StatusNotFound {
		return nil, fmt.Errorf("template not found: %s/%s/%s", kind, namespace, name)
	}

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("workload manager returned status %d", resp.StatusCode)
	}

	var createResp types.CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&createResp); err != nil {
		return nil, err
	}

	if createResp.SessionID == "" {
		return nil, fmt.Errorf("session ID is empty in response")
	}

	sandbox := &types.SandboxInfo{
		Kind:             kind,
		SandboxID:        createResp.SandboxID,
		Name:             createResp.SandboxName,
		SessionID:        createResp.SessionID,
		EntryPoints:      createResp.EntryPoints,
		SandboxNamespace: namespace,
	}

	return sandbox, nil
}

func getResourcePath(kind string) string {
	switch kind {
	case types.AgentRuntimeKind:
		return "agent-runtime"
	case types.CodeInterpreterKind:
		return "code-interpreter"
	default:
		return "agent-runtime"
	}
}

// UpdateLastActivity updates the last activity timestamp for a session
func (sm *SessionManager) UpdateLastActivity(ctx context.Context, sessionID string) {
	if err := sm.store.UpdateSessionLastActivity(ctx, sessionID, time.Now()); err != nil {
		klog.Warningf("Failed to update last activity for session %s: %v", sessionID, err)
	}
}

